import{_ as o,o as a,c as r,a2 as t}from"./chunks/framework.IwO0Hdn_.js";const u=JSON.parse('{"title":"[DATA] F-05.1 — Conexión a PostgreSQL Existente","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-05.1_conexion_postgresql.md","filePath":"backlog/F-05.1_conexion_postgresql.md","lastUpdated":null}'),n={name:"backlog/F-05.1_conexion_postgresql.md"};function s(c,e,i,d,l,g){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="data-f-05-1-—-conexion-a-postgresql-existente" tabindex="-1">[DATA] F-05.1 — Conexión a PostgreSQL Existente <a class="header-anchor" href="#data-f-05-1-—-conexion-a-postgresql-existente" aria-label="Permalink to &quot;[DATA] F-05.1 — Conexión a PostgreSQL Existente&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-05 — Infraestructura y Conectividad</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Data</code><strong>Secundaria:</strong> <code>Infrastructure</code><strong>Impacta en:</strong> Equipo Base de Datos + Equipo Backend (Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.1_setup_laravel_livewire.html">F-00.1</a></td><td>Laravel instalado con driver <code>pgsql</code> disponible en Composer</td></tr><tr><td><a href="./F-00.2_migraciones_modelos.html">F-00.2</a></td><td>Migraciones a ejecutar requieren la conexión activa</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como desarrollador del sistema Quiero que Laravel 12 se conecte a la base de datos PostgreSQL existente con permisos mínimos necesarios Para reutilizar la infraestructura existente sin duplicar datos ni crear riesgos de seguridad</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Conexión exitosa):</strong> Dado que la configuración de <code>.env</code> contiene las credenciales correctas, cuando la aplicación arranca, entonces Laravel establece la conexión con PostgreSQL sin errores.</li><li>[ ] <strong>Escenario 2 (Permisos mínimos):</strong> Dado que el usuario de BD del panel está configurado, cuando intenta hacer DELETE sobre <code>archived_logs</code>, entonces recibe un error de permisos insuficientes (no se permite por diseño).</li><li>[ ] <strong>Escenario 3 (Credenciales seguras):</strong> Dado que el repositorio es inspeccionado, cuando se buscan credenciales en el código fuente o en archivos versionados, entonces no se encuentran (están solo en <code>.env</code> excluido de git).</li><li>[ ] <strong>Requisito Técnico:</strong> Usuario de DB dedicado con permisos: <code>SELECT</code> en <code>logs</code>; <code>SELECT, INSERT, UPDATE</code> en <code>archived_logs</code>, <code>comments</code>, <code>error_codes</code> y <code>error_code_comments</code>; <code>SELECT, INSERT</code> en <code>users</code>. <strong>Nota:</strong> si se implementa F-04.9 (COULD — borrar entrada de histórico), deberá añadirse el permiso <code>DELETE</code> sobre <code>archived_logs</code> para ese entorno. Credenciales en variables de entorno <code>.env</code> (STRIDE I-DB-01). El schema de la tabla <code>logs</code> debe documentarse antes del desarrollo (Restricción Técnica #1).</li></ul>',12)])])}const m=o(n,[["render",s]]);export{u as __pageData,m as default};
